[22] يُنظر: ((تفسير ابن جرير)) (17/10)، ((تفسير ابن عطية)) (4/136)، ((تفسير السعدي)) (ص: 548). قال ابن الجوزي: (وفي المرادِ باللَّغوِ هاهنا خمسةُ أقوالٍ: أحدُها: الشِّركُ. رواه أبو صالحٍ عن ابنِ عبَّاسٍ. والثاني: الباطِلُ. رواه ابنُ أبي طلحةَ عن ابنِ عبَّاسٍ. والثالثُ: المعاصي. قاله الحَسَنُ. والرابعُ: الكَذِبُ. قاله السُّدِّيُّ. والخامسُ: الشَّتمُ والأذى الذي كانوا يَسمَعونَه مِن الكُفَّارِ. قاله مقاتِلٌ. قال الزَّجَّاج: واللَّغوُ: كُلُّ لَعِبٍ ولَهوٍ، وكلُّ مَعصيةٍ فهي مُطَّرَحةٌ مُلغاةٌ، فالمعنى: شَغَلَهم الجِدُّ فيما أمَرَهم اللهُ به عن اللَّغوِ). ((تفسير ابن الجوزي)) (3/256). ويُنظر: ((تفسير مقاتل بن سليمان)) (3/152)، ((معاني القرآن وإعرابه)) للزجاج (4/6). وممَّن قَصَر اللَّغوَ على ساقِطِ الكلامِ: السمرقندي، وابن عطية، والنَّسَفي. يُنظر: ((تفسير السمرقندي)) (2/473)، ((تفسير ابن عطية)) (4/136)، ((تفسير النسفي)) (2/459)، ((تفسير ابن جزي))  (2/48). قال ابنُ جُزَي: (اللَّغوُ هنا: السَّاقِطُ مِن الكلامِ؛ كالسَّبِّ واللَّهوِ، والكلامِ بما لا يَعني، وعددُ أنواعِ المنهيِّ عنه من الكلامِ عِشرون نَوعًا، ومعنى الإعراضِ عنه: عدمُ الاستماعِ إليه والدُّخولِ فيه، ويحتَمِلُ أن يريدَ أنَّهم لا يتكلَّمونَ به، ولكِنَّ إعراضَهم عن سَماعِه يقتضي ذلك من بابِ أَولى وأَحرى). ((تفسير ابن جزي)) (2/48). وقيل: اللَّغوُ هو ما لا يَعنيك مِن قَولٍ أو فِعلٍ؛ كاللَّعِبِ والهَزلِ. وممَّن اختاره: الزمخشري، والبيضاوي، وأبو السعود، والقاسمي. يُنظر: ((تفسير الزمخشري)) (3/175)، ((تفسير البيضاوي)) (4/82)، ((تفسير أبي السعود)) (6/123)، ((تفسير القاسمي)) (7/281). وممَّن اختار أنَّ المرادَ به: الباطِلُ وما يَكرَهُه اللهُ: ابنُ جرير، ومكِّي، وابن كثير. يُنظر:  ((تفسير ابن جرير)) (17/10)، ((الهداية)) لمكي (7/4943)، ((تفسير ابن كثير)) (5/462). قال ابن كثير: (وَالَّذِينَ هُمْ عَنِ اللَّغْوِ مُعْرِضُونَ أي: عن الباطِلِ، وهو يَشمَلُ: الشِّركَ -كما قاله بعضُهم-، والمعاصيَ -كما قاله آخَرون-، وما لا فائِدةَ فيه من الأقوالِ والأفعالِ، كما قال تعالى: وَإِذَا مَرُّوا بِاللَّغْوِ مَرُّوا كِرَامًا
[الفرقان: 72]
). ((تفسير ابن كثير)) (5/462). وقال النيسابوري: (وَالَّذِينَ هُمْ عَنِ اللَّغْوِ مُعْرِضُونَ اللَّغوُ... يَشمَلُ كُلَّ ما كان حرامًا، أو مكروهًا، أو مباحًا لا ضرورةَ إليه ولا حاجةَ قَولًا أو فِعلًا). ((تفسير النيسابوري)) (5/109). وقال الواحدي: (وَالَّذِينَ هُمْ عَنِ اللَّغْوِ مُعْرِضُونَ عن كلِّ ما لا يَجمُلُ في الشَّرعِ مِن قَولٍ وفِعلٍ). ((الوجيز)) (ص: 743).

[111] يُنظر: ((تفسير الرسعني)) (5/106)، ((تفسير العليمي)) (4/460)، ((تفسير السعدي)) (ص: 548). وممن اختار أنَّ المرادَ بالإنسانِ: آدمُ: مقاتلُ بنُ سليمان، ويحيى بن سلام، والزجَّاج، والسمرقندي، والقصَّاب، وابن أبي زمنين، وابن كثير، وابن القيم، والعُليمي، والسعدي، وابنُ عثيمين. يُنظر: ((تفسير مقاتل بن سليمان)) (3/153)، ((تفسير يحيى بن سلام)) (1/394)، ((معاني القرآن وإعرابه)) للزجاج (4/8)، ((تفسير السمرقندي)) (2/475)، ((النكت الدالة على البيان)) للقصاب (2/345)، ((تفسير ابن أبي زمنين)) (3/196)، ((تفسير ابن كثير)) (5/465)، ((التبيان في أقسام القرآن)) لابن القيم (ص: 263)، ((هداية الحيارى)) لابن القيم (2/582)، ((تفسير العليمي)) (4/460)، ((تفسير السعدي)) (ص: 548)، ((تفسير ابن عثيمين: الحجرات - الحديد)) (ص: 272). قال ابن كثير: (وقال قتادَةُ: استُلَّ آدمُ مِنَ الطِّينِ. وهذا أظهرُ في المعنَى، وأقربُ إِلى السِّياقِ، فإنَّ آدَمَ عليه السَّلامُ خُلِق مِن طينٍ لازِبٍ، وهو الصَّلصالُ مِنَ الحمَأِ المسنونِ، وذلك مخلوقٌ مِنَ التُّرابِ، كما قالَ تعالَى: وَمِنْ آَيَاتِهِ أَنْ خَلَقَكُمْ مِنْ تُرَابٍ ثُمَّ إِذَا أَنْتُمْ بَشَرٌ تَنْتَشِرُونَ
[الروم: 20]
). ((تفسير ابن كثير)) (5/465). وقال ابنُ عاشور في معنى السُّلالةِ بِناءً على هذا القولِ: (السُّلالةُ: الطِّينَةُ الخاصَّةُ الَّتي كَوَّن اللَّهُ منها آدمَ، وهي الصَّلْصالُ الَّذي مَيَّزَه مِنَ الطِّينِ في مبدأِ الخليقةِ، فتلك الطِّينةُ مسلولةٌ سَلًّا خاصًّا مِنَ الطِّينِ ليتكَوَّنَ منها حَيٌّ). ((تفسير ابن عاشور)) (18/23). وقيل: المرادُ بالإنسانِ: ابنُ آدمَ. وممن اختار هذا القولَ: ابنُ جريرٍ، والثعلبي، والسمعاني، والواحدي، والبغوي، والخازن، والشوكاني. يُنظر: ((تفسير ابن جرير)) (17/19)، ((تفسير الثعلبي)) (7/42)، ((تفسير السمعاني)) (3/466)، ((الوسيط)) للواحدي (3/285)، ((تفسير البغوي)) (3/361)، ((تفسير الخازن)) (3/269)، ((تفسير الشوكاني)) (3/564). قال ابنُ الجوزي: (وَلَقَدْ خَلَقْنَا الْإِنْسَانَ فيه قولان: أحدُهما: أنَّه آدمُ عليه السَّلامُ، وإنَّما قيل: مِنْ سُلَالَةٍ؛ لأنَّه استُلَّ مِن كُلِّ الأرضِ. هذا مذهبُ سلمانَ الفارسيِّ، وابنِ عبَّاسٍ في روايةٍ، وقتادةَ. والثاني: أنَّه ابنُ آدم، والسُّلالةُ: النُّطفةُ استُلَّت من الطينِ، والطينُ: آدمُ عليه السلامُ. قاله أبو صالحٍ عن ابن عباسٍ. قال الزجَّاج: والسُّلالةُ: فُعالةٌ، وهي القليلُ مما يَنسَلُّ). ((تفسير ابن الجوزي)) (3/257). وقال السمعاني: (وقولُه: مِنْ طِينٍ الطينُ هاهُنا هو آدمُ، وعليه الأكثرونَ). ((تفسير السمعاني)) (3/466). وقال ابن جُزي: (ويحتملُ عندي أن يرادَ بالإنسانِ الجنسُ الذي يعُمُّ آدمَ وذريتَه، فأجمَلَ ذِكرَ الإنسانِ أوَّلًا، ثم فصَّلَه بعد ذلك إلى الخِلقةِ المختصَّةِ بآدمَ: وهي من طينٍ، وإلى الخِلقةِ المختصَّةِ بذريَّتِه، وهي النطفةُ). ((تفسير ابن جزي)) (2/49). وقولُه: مِنْ سُلَالَةٍ مِنْ طِينٍ (مِن) الأولى ابتدائيَّةٌ متعلِّقةٌ بالخَلقِ، و(مِنْ) الثانية بيانيَّةٌ متعلِّقةٌ بمحذوفٍ وقَعَ صفةً لسُلالة، أي: خلقناهُ مِن سُلالةٍ كائنةٍ مِن طينٍ. ويجوزُ أنْ تتعلَّق بسُلالة على أنَّها بمعنى مسلولةٍ؛ فهي ابتدائيَّةٌ كالأُولى. يُنظر: ((تفسير الزمخشري)) (3/178)، ((تفسير البيضاوي)) (4/83)، ((تفسير أبي حيان)) (7/550، 551)، ((تفسير أبي السعود)) (6/126).

[173] يُنظر: ((تفسير ابن جرير)) (17/27)، ((تفسير القرطبي)) (12/112). قال السعدي: (وَإِنَّا عَلَى ذَهَابٍ بِهِ لَقَادِرُونَ إمَّا بألَّا نُنزِلَه، أو نُنزِلَه فيَذهبَ نازِلًا لا يُوصَلُ إليه، أو لا يُوجَدُ منه المقصودُ منه، وهذا تنبيهٌ منه لعبادِه أن يشكُروه على نِعمَتِه، ويقَدِّروا عَدَمَها، ماذا يحصُلُ به مِنَ الضَّرَرِ، كقولِه تعالى: قُلْ أَرَأَيْتُمْ إِنْ أَصْبَحَ مَاؤُكُمْ غَوْرًا فَمَنْ يَأْتِيكُمْ بِمَاءٍ مَعِينٍ
[الملك: 30]
). ((تفسير السعدي)) (ص: 549).
